// hooks/useRecurringTemplates.ts
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '@/lib/db';
import type { RecurringTemplate } from '@/types';

export function useRecurringTemplates() {
  const templates = useLiveQuery(() => db.recurringTemplates.toArray());
  const create = async (t: Omit<RecurringTemplate, 'id'>) => db.recurringTemplates.add(t);
  const update = async (id: string, changes: Partial<RecurringTemplate>) => db.recurringTemplates.update(id, changes);
  const remove = async (id: string) => {
    await db.expenses.where('recurringTemplateId').equals(id).modify({ recurringTemplateId: null });
    await db.recurringTemplates.delete(id);
  };
  return { templates, create, update, remove };
}

