// lib/recurrence.ts
const cache = new Map<string, Date[]>();

export function computeUpcoming(
  template: RecurringTemplate,
  windowStart: Date,
  windowEnd: Date
): Date[] {
  const key = `${template.id}:${windowStart.toISOString()}:${windowEnd.toISOString()}`;
  if (cache.has(key)) return cache.get(key)!;
  const dates: Date[] = [];
  // ... compute dates based on frequency, startDate, endDate
  cache.set(key, dates);
  return dates;
}

export function invalidateOccurrenceCache(templateId?: string) {
  if (templateId) {
    for (const key of cache.keys()) {
      if (key.startsWith(templateId)) cache.delete(key);
    }
  } else {
    cache.clear();
  }
}

// In useRecurringTemplates hook
const remove = async (id: string, mode: 'single' | 'series', expenseId?: string) => {
  await db.transaction('rw', db.expenses, db.recurringTemplates, async () => {
    if (mode === 'single' && expenseId) {
      await db.expenses.update(expenseId, { recurringTemplateId: null });
    } else {
      await db.expenses.where('recurringTemplateId').equals(id).modify({ recurringTemplateId: null });
      await db.recurringTemplates.delete(id);
    }
  });
  invalidateOccurrenceCache(id);
};

// lib/logger.ts
const isDev = import.meta.env.DEV;

export const logger = {
  info: (action: string, meta?: Record<string, unknown>) => {
    if (isDev) console.log(JSON.stringify({ ts: Date.now(), level: 'info', action, ...meta }));
  },
  error: (action: string, error: unknown, meta?: Record<string, unknown>) => {
    console.error(JSON.stringify({ ts: Date.now(), level: 'error', action, error: String(error), ...meta }));
  },
};

// lib/db.ts
import Dexie from 'dexie';

export const db = new Dexie('CashPulseDB');

db.version(1).stores({
  expenses: '++id, categoryId, date, paymentMethod',
  categories: '++id, name',
});

db.version(2).stores({
  expenses: '++id, categoryId, date, paymentMethod, recurringTemplateId',
  categories: '++id, name',
  recurringTemplates: '++id, categoryId, frequency, status, nextOccurrence',
}).upgrade(tx => {
  // Existing expenses get null recurringTemplateId by default
  return tx.table('expenses').toCollection().modify(exp => {
    if (exp.recurringTemplateId === undefined) exp.recurringTemplateId = null;
  });
});

